files.content:
body {
  margin: 0;
  font-family: 'Segoe UI', sans-serif;
  background: #f7f8fb;
  color: #17212c;
}

main {
  width: min(860px, 92vw);
  margin: 2rem auto;
  padding: 1.25rem;
  border-radius: 0.9rem;
  background: #ffffff;
  box-shadow: 0 12px 30px rgba(15, 33, 51, 0.08);
}

img {
  width: min(100%, 420px);
  min-height: 120px;
  border: 1px dashed #8ea0b5;
  background: #f1f4f9;
}
